mapper.select:
select cl.id, cl.label_name, cl.label_code, cl.merchant_id, cl.create_time, cl.update_time, cl.state,
       cmi.merchant_name as merchantName
from cm_label cl left join cm_merchant_info cmi on cl.merchant_id = cmi.id
where cl.deleted = '0' and cmi.deleted = '0'

	and cl.merchant_id = #{vo.merchantId}


	and cl.label_code = #{vo.labelCode}


	and cl.label_name like concat('%', #{vo.labelName}, '%')


	and cl.state = #{vo.state}

order by cl.create_time desc
